mapper.insert:

			SELECT SEQ_FILE.nextval FROM DUAL

    insert all
      into FILE_INFO(FILE_NO, ORIGINAL_NAME, CHANGED_NAME, MIME,
        FILE_SIZE, SAVE_PATH, SAVED_AT, EXPIRE_ON)
      values(
        #{fileNo}
        ,#{originalName}
        ,#{changedName}
        ,#{mime}
        ,#{fileSize}
        ,#{savePath}
        ,#{savedAt}
        ,#{expireOn}
      )

      into COMPANY_DOC(COMPANY_NO, FILE_NO, DOC_TYPE)
      values(
        #{companyNo}
        ,#{fileNo}
        ,#{docType}
      )
    select * from dual
